import{_ as s,o as n,c as e,a2 as t}from"./chunks/framework.y1bVONfd.js";const u=JSON.parse('{"title":"会话记忆召回","description":"通过 @recall 实现会话上下文自动恢复","frontmatter":{"title":"会话记忆召回","description":"通过 @recall 实现会话上下文自动恢复"},"headers":[],"relativePath":"zh/guide/memory-recall.md","filePath":"zh/guide/memory-recall.md"}'),i={name:"zh/guide/memory-recall.md"};function l(o,a,p,d,r,c){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="会话记忆召回" tabindex="-1">会话记忆召回 <a class="header-anchor" href="#会话记忆召回" aria-label="Permalink to &quot;会话记忆召回&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>当客户端因重启、网络中断或设备切换丢失上下文时，WebRouter 的会话记忆召回机制自动从服务端恢复对话历史，注入回请求中。</p><p>无需客户端存储，无需复杂的状态管理，只需一个简单的触发。</p><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端断开</span></span>
<span class="line"><span>     │</span></span>
<span class="line"><span>     ▼</span></span>
<span class="line"><span>┌─────────────┐     POST /v1/chat/completions     ┌──────────────┐</span></span>
<span class="line"><span>│   客户端      │ ────────────────────────────────→ │   wr-proxy    │</span></span>
<span class="line"><span>│ (无历史记录)  │    @recall 还记得之前聊的...        │               │</span></span>
<span class="line"><span>└─────────────┘                                    └──────┬────────┘</span></span>
<span class="line"><span>                                                          │</span></span>
<span class="line"><span>                                                   ┌──────▼────────┐</span></span>
<span class="line"><span>                                                   │ wr_session_    │</span></span>
<span class="line"><span>                                                   │ messages       │</span></span>
<span class="line"><span>                                                   │ (SQLite)       │</span></span>
<span class="line"><span>                                                   └──────┬────────┘</span></span>
<span class="line"><span>                                                          │</span></span>
<span class="line"><span>                                                   ┌──────▼────────┐</span></span>
<span class="line"><span>                                                   │ 将历史注入      │</span></span>
<span class="line"><span>                                                   │ messages 数组   │</span></span>
<span class="line"><span>                                                   │ (Token预算感知) │</span></span>
<span class="line"><span>                                                   └──────┬────────┘</span></span>
<span class="line"><span>                                                          │</span></span>
<span class="line"><span>                                                          ▼</span></span>
<span class="line"><span>                                                    上游 LLM</span></span></code></pre></div><h2 id="触发方式" tabindex="-1">触发方式 <a class="header-anchor" href="#触发方式" aria-label="Permalink to &quot;触发方式&quot;">​</a></h2><h3 id="_1-recall-魔术词" tabindex="-1">1. <code>@recall</code> 魔术词 <a class="header-anchor" href="#_1-recall-魔术词" aria-label="Permalink to &quot;1. \`@recall\` 魔术词&quot;">​</a></h3><p>在用户消息中任意位置包含 <code>@recall</code>，wr-proxy 会检测并剥离，然后注入会话历史。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User: @recall 我们之前讨论的第三点是什么？</span></span></code></pre></div><p><code>@recall</code> 标记在消息到达上游模型前被移除。</p><h3 id="_2-自然语言触发" tabindex="-1">2. 自然语言触发 <a class="header-anchor" href="#_2-自然语言触发" aria-label="Permalink to &quot;2. 自然语言触发&quot;">​</a></h3><p>当客户端无上下文（messages 中没有 assistant 回复）时，以下短语自动触发召回：</p><table tabindex="0"><thead><tr><th>短语</th></tr></thead><tbody><tr><td>还记得</td></tr><tr><td>继续上次</td></tr><tr><td>继续聊</td></tr><tr><td>接着说</td></tr><tr><td>之前聊过</td></tr><tr><td>上次说到</td></tr><tr><td>接着上次</td></tr></tbody></table><h3 id="_3-http-header" tabindex="-1">3. HTTP Header <a class="header-anchor" href="#_3-http-header" aria-label="Permalink to &quot;3. HTTP Header&quot;">​</a></h3><p>发送 <code>X-Recall-Session: &lt;session_id&gt;</code> 显式触发特定会话的召回。</p><h2 id="token-预算控制" tabindex="-1">Token 预算控制 <a class="header-anchor" href="#token-预算控制" aria-label="Permalink to &quot;Token 预算控制&quot;">​</a></h2><p>召回的历史消息受 Token 预算限制（默认 8000 tokens）。wr-proxy 从最新到最旧累积消息，直到预算用完，确保最近上下文优先保留。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>最近轮次  ←  优先注入（在预算内）</span></span>
<span class="line"><span>早期轮次  ←  超出预算时省略</span></span>
<span class="line"><span>系统提示词 ←  始终保留在顶部</span></span></code></pre></div><p>通过系统设置 <code>session_recall_budget</code> 配置。</p><h2 id="会话消息存储" tabindex="-1">会话消息存储 <a class="header-anchor" href="#会话消息存储" aria-label="Permalink to &quot;会话消息存储&quot;">​</a></h2><p>每轮对话（user + assistant 对）异步持久化到 <code>wr_session_messages</code>：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>session_id</code></td><td>唯一会话标识（来自 <code>X-Session-Id</code> 头）</td></tr><tr><td><code>token_id</code></td><td>所属 Token</td></tr><tr><td><code>turn_index</code></td><td>会话内递增轮次号</td></tr><tr><td><code>role</code></td><td><code>user</code> 或 <code>assistant</code></td></tr><tr><td><code>content</code></td><td>消息内容（已脱敏）</td></tr><tr><td><code>model</code></td><td>本次响应用到的模型</td></tr></tbody></table><h2 id="保留策略" tabindex="-1">保留策略 <a class="header-anchor" href="#保留策略" aria-label="Permalink to &quot;保留策略&quot;">​</a></h2><p>旧会话根据 <code>session_recall_retention_days</code> 自动清理（默认 30 天），每 6 小时执行一次。</p><h2 id="启用会话召回" tabindex="-1">启用会话召回 <a class="header-anchor" href="#启用会话召回" aria-label="Permalink to &quot;启用会话召回&quot;">​</a></h2><p>按 Token 配置：</p><ol><li>进入 <strong>令牌管理</strong> → 选择 Token</li><li>启用 <strong>会话记忆召回</strong></li><li>客户端请求需携带 <code>X-Session-Id</code> 头</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:5051/v1/chat/completions</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer &lt;token&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;X-Session-Id: my-session-001&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;model&quot;: &quot;gpt-4o&quot;, &quot;messages&quot;: [{&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;@recall 继续我们的讨论&quot;}]}&#39;</span></span></code></pre></div><h2 id="架构说明" tabindex="-1">架构说明 <a class="header-anchor" href="#架构说明" aria-label="Permalink to &quot;架构说明&quot;">​</a></h2><ul><li><strong>异步落盘</strong>：消息通过缓冲 channel + 单 goroutine 顺序写入，对请求转发零延迟影响</li><li><strong>脱敏优先</strong>：内容在脱敏规则处理后存储</li><li><strong>Token 隔离</strong>：每个 Token 的会话严格隔离，不可跨 Token 召回</li><li><strong>轮次完整性</strong>：turn_index 按会话顺序分配，防止乱序</li></ul>`,31)])])}const k=s(i,[["render",l]]);export{u as __pageData,k as default};
